      y = (v.y * (sMs - xyMxy) - 2.0 * sMxy * v.x),
    )

  infix def sandwich(v: Pga2dPoint): Pga2dProjectivePoint =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dProjectivePoint(
      x = (v.x * (sMs - xyMxy) + 2.0 * sMxy * v.y),
      y = (v.y * (sMs - xyMxy) - 2.0 * sMxy * v.x),
      w = (sMs + xyMxy),
    )

  infix def sandwich(v: Pga2dLineIdeal): Pga2dLineIdeal =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dLineIdeal(
      x = (v.x * (sMs - xyMxy) + 2.0 * sMxy * v.y),
      y = (v.y * (sMs - xyMxy) - 2.0 * sMxy * v.x),
    )

  infix def sandwich(v: Pga2dPseudoScalar): Pga2dPseudoScalar =
    Pga2dPseudoScalar(
      i = v.i * (s * s + xy * xy),
    )

  infix def sandwich(v: Pga2dPointCenter.type): Pga2dRotor =
    Pga2dRotor(
      s = 0.0,
      xy = (s * s + xy * xy),
    )

  infix def reverseSandwich(v: Pga2dMotor): Pga2dMotor =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dMotor(
      s = v.s * (sMs + xyMxy),
      wx = (v.wx * (sMs - xyMxy) - 2.0 * sMxy * v.wy),
      wy = (v.wy * (sMs - xyMxy) + 2.0 * sMxy * v.wx),
      xy = v.xy * (sMs + xyMxy),
    )

  infix def reverseSandwich(v: Pga2dLine): Pga2dLine =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dLine(
      x = (v.x * (sMs - xyMxy) - 2.0 * sMxy * v.y),
      y = (v.y * (sMs - xyMxy) + 2.0 * sMxy * v.x),
      w = v.w * (sMs + xyMxy),
    )

  infix def reverseSandwich(v: Pga2dProjectivePoint): Pga2dProjectivePoint =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dProjectivePoint(
      x = (v.x * (sMs - xyMxy) - 2.0 * sMxy * v.y),
      y = (v.y * (sMs - xyMxy) + 2.0 * sMxy * v.x),
      w = v.w * (sMs + xyMxy),
    )

  infix def reverseSandwich(v: Pga2dRotor): Pga2dRotor =
    val sMs = s * s
    val xyMxy = xy * xy
    Pga2dRotor(
      s = v.s * (sMs + xyMxy),
      xy = v.xy * (sMs + xyMxy),
    )

  infix def reverseSandwich(v: Pga2dProjectiveTranslator): Pga2dProjectiveTranslator =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dProjectiveTranslator(
      s = v.s * (sMs + xyMxy),
      wx = (v.wx * (sMs - xyMxy) - 2.0 * sMxy * v.wy),
      wy = (v.wy * (sMs - xyMxy) + 2.0 * sMxy * v.wx),
    )

  infix def reverseSandwich(v: Pga2dTranslator): Pga2dProjectiveTranslator =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dProjectiveTranslator(
      s = (sMs + xyMxy),
      wx = (v.wx * (sMs - xyMxy) - 2.0 * sMxy * v.wy),
      wy = (v.wy * (sMs - xyMxy) + 2.0 * sMxy * v.wx),
    )

  infix def reverseSandwich(v: Pga2dVector): Pga2dVector =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dVector(
      x = (v.x * (sMs - xyMxy) - 2.0 * sMxy * v.y),
      y = (v.y * (sMs - xyMxy) + 2.0 * sMxy * v.x),
    )

  infix def reverseSandwich(v: Pga2dPoint): Pga2dProjectivePoint =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dProjectivePoint(
      x = (v.x * (sMs - xyMxy) - 2.0 * sMxy * v.y),
      y = (v.y * (sMs - xyMxy) + 2.0 * sMxy * v.x),
      w = (sMs + xyMxy),
    )

  infix def reverseSandwich(v: Pga2dLineIdeal): Pga2dLineIdeal =
    val sMs = s * s
    val sMxy = s * xy
    val xyMxy = xy * xy
    Pga2dLineIdeal(
      x = (v.x * (sMs - xyMxy) - 2.0 * sMxy * v.y),
      y = (v.y * (sMs - xyMxy) + 2.0 * sMxy * v.x),
    )

  infix def reverseSandwich(v: Pga2dPseudoScalar): Pga2dPseudoScalar =
    Pga2dPseudoScalar(
      i = v.i * (s * s + xy * xy),
    )

  infix def reverseSandwich(v: Pga2dPointCenter.type): Pga2dRotor =
    Pga2dRotor(
      s = 0.0,
      xy = (s * s + xy * xy),
    )

  infix def cross(v: Pga2dMotor): Pga2dVector =
    Pga2dVector(
      x = v.wx * xy,
      y = v.wy * xy,
    )

  infix def cross(v: Pga2dLine): Pga2dLineIdeal =
    Pga2dLineIdeal(
      x = v.y * xy,
      y = -v.x * xy,
    )

  infix def cross(v: Pga2dProjectivePoint): Pga2dVector =
    Pga2dVector(
      x = v.y * xy,
      y = -v.x * xy,
    )

  infix def cross(v: Pga2dProjectiveTranslator): Pga2dVector =
    Pga2dVector(
      x = v.wx * xy,
      y = v.wy * xy,
    )

  infix def cross(v: Pga2dTranslator): Pga2dVector =
    Pga2dVector(
      x = v.wx * xy,
      y = v.wy * xy,
    )

  infix def cross(v: Pga2dVector): Pga2dVector =
    Pga2dVector(
      x = v.y * xy,
      y = -v.x * xy,
    )

  infix def cross(v: Pga2dPoint): Pga2dVector =
    Pga2dVector(
      x = v.y * xy,
      y = -v.x * xy,
    )

  infix def cross(v: Pga2dLineIdeal): Pga2dLineIdeal =
    Pga2dLineIdeal(
      x = v.y * xy,
      y = -v.x * xy,
    )


object Pga2dRotor:

  inline val componentsCount = 2

  val id: Pga2dRotor = Pga2dRotor(1.0, 0.0)

  def rotation(from: Pga2dLineIdeal, to: Pga2dLineIdeal): Pga2dRotor = {
    // not Math.sqrt(from.normSquare * to.normSquare): the product overflows/underflows
    // for extreme magnitudes (~1e100 or ~1e-100) where each norm alone is still fine
    val norm = from.norm * to.norm
    val r2a = to.geometric(from) / norm
    val dot = r2a.s

    if (dot > -1.0 + 1e-6) {
      val newCos = Math.sqrt((1.0 + dot) / 2.0)
      val newSinDivSin2 = 0.5 / newCos
      return Pga2dRotor(newCos, r2a.xy * newSinDivSin2)
    }

    val sin2a = Math.abs(r2a.xy)
    if (sin2a > 1e-8) {
      val angle2 = Math.atan2(sin2a, r2a.s)
      val propAngle = angle2 * 0.5
      val mult = Math.sin(propAngle) / sin2a
      return Pga2dRotor(Math.cos(propAngle), r2a.xy * mult).normalizedByNorm
    }

    // nearly a rotation by pi: the full angle is pi - eps with sin(eps) = sin2a <= 1e-8.
    // first-order half-angle rotor: s = sin(eps/2) = 0.5 * sin2a * (1 + eps^2/8 + O(eps^4)) and
    // xy = +-cos(eps/2) = +-(1 - eps^2/8); at eps <= 1e-8 the dropped eps^2/8 <= 1.25e-17 terms
    // are below 2^-53, so both components are exact in double. xy carries the sign of r2a.xy,
    // matching the atan2 branch above, so the result is continuous across the sin2a threshold;
    // sin2a == 0 (exactly antipodal inputs) gives the exact pi rotor (0, 1)
    Pga2dRotor(0.5 * sin2a, if (r2a.xy < 0.0) -1.0 else 1.0)
  }

  def rotation(from: Pga2dVector, to: Pga2dVector): Pga2dRotor =
    rotation(from.dual, to.dual)

  /** restore rotor from a rotated orthonormal basis (columns of a 2x2 rotation matrix),
   *  so that restored.sandwich(Pga2dVector(1, 0)) == axisX and restored.sandwich(Pga2dVector(0, 1)) == axisY.
   *  axisY is redundant in 2d (SO(2) has one degree of freedom), it is used only to symmetrize rounding errors,
   *  in the same way as Pga3dQuaternion.restore uses (m01 - m10) */
  def restore(axisX: Pga2dVector, axisY: Pga2dVector): Pga2dRotor = {
    val cosT = 0.5 * (axisX.x + axisY.y)
    val sinT = 0.5 * (axisY.x - axisX.y)
    // both branches give the same rotor; -0.9 is not a correctness boundary, it only picks
    // the better-conditioned half-angle form: (1 + cosT) loses precision near the angle pi
    if (cosT > -0.9) Pga2dRotor(1.0 + cosT, sinT).normalizedByNorm
    else Pga2dRotor(sinT, 1.0 - cosT).normalizedByNorm
  }